import React, { useState } from 'react'; 
import '../styles/Login.css';
import { useNavigate } from 'react-router-dom'; // Added useNavigate for redirection

function Login() {
  // 1. Create state for the input fields
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault(); // Prevents the page from refreshing
    setError('');

    // 2. Simple Frontend Validation
    if (!email || !password) {
      setError('Please fill in all fields');
      return;
    }

    // 3. Simulate an API Call
    // In a real app, you'd send this to your backend
    if (email === "user@hirehub.com" && password === "password123") {
      
      // 4. Set the "Gate" (Session Management)
      localStorage.setItem('userToken', 'secure-jwt-string');
      
      // 5. Redirect to the Find Jobs page
      navigate('/find-jobs');
    } else {
      setError('Invalid email or password. Try user@hirehub.com');
    }
  };
    return (
    <div className="login-container">
      <form className="login-form" onSubmit={handleLogin}>
        <h2>Welcome Back</h2>
        
        {error && <p className="error-message">{error}</p>}

        <div className="input-group">
          <label>Email</label>
          <input 
            type="email" 
            value={email}
            onChange={(e) => setEmail(e.target.value)} 
            placeholder="Enter your email"
          />
        </div>

        <div className="input-group">
          <label>Password</label>
          <input 
            type="password" 
            value={password}
            onChange={(e) => setPassword(e.target.value)} 
            placeholder="Enter your password"
          />
        </div>

        <button type="submit" className="login-btn">Login</button>
      </form>
    </div>
  );
}

export default Login;
